/* Simple JSON string extractor - finds "key":"value" and returns value (unescaped) */
static char *json_get_string(const char *json, const char *key) {
    char search[256];
    snprintf(search, sizeof(search), "\"%s\"", key);
    const char *p = strstr(json, search);
    if (!p) return NULL;
    p += strlen(search);
    /* skip whitespace and colon */
    while (*p && (*p == ' ' || *p == '\t' || *p == '\n' || *p == '\r')) p++;
    if (*p != ':') return NULL;
    p++;
    while (*p && (*p == ' ' || *p == '\t' || *p == '\n' || *p == '\r')) p++;
    if (*p == 'n' && strncmp(p, "null", 4) == 0) return NULL;
    if (*p != '"') return NULL;
    p++;
    /* extract string value, handling escapes */
    size_t cap = 1024;
    char *result = malloc(cap);
    size_t len = 0;
    while (*p && *p != '"') {
        if (len + 6 >= cap) {
            cap *= 2;
            result = realloc(result, cap);
        }
        if (*p == '\\') {
            p++;
            switch (*p) {
                case '"': result[len++] = '"'; break;
                case '\\': result[len++] = '\\'; break;
                case '/': result[len++] = '/'; break;
                case 'n': result[len++] = '\n'; break;
                case 'r': result[len++] = '\r'; break;
                case 't': result[len++] = '\t'; break;
                case 'b': result[len++] = '\b'; break;
                case 'f': result[len++] = '\f'; break;
                case 'u': {
                    /* just copy \uXXXX as-is for simplicity */
                    result[len++] = '\\'; result[len++] = 'u';
                    for (int i = 0; i < 4 && p[1]; i++) {
                        p++;
                        result[len++] = *p;
                    }
                    break;
                }
                default: result[len++] = *p; break;
            }
        } else {
            result[len++] = *p;
        }
        p++;
    }
    result[len] = '\0';
    return result;
}

/* Check if title is present and non-empty (after trimming) */
static int title_valid(const char *title) {
    if (!title) return 0;
    /* Check if all whitespace */
    const char *p = title;
    while (*p) {
        if (!isspace((unsigned char)*p)) return 1;
        p++;
    }
    return 0; /* empty or all whitespace */
}

static int parse_id_from_url(const char *url) {
    /* url is like /api/notes/123 */
    const char *p = url + strlen("/api/notes/");
    if (!*p) return -1;
    /* check all digits */
    const char *s = p;
    while (*s) {
        if (!isdigit((unsigned char)*s)) return -1;
        s++;
    }
    return atoi(p);
}

enum MHD_Result route_request(struct MHD_Connection *connection, const char *url,
                              const char *method, const char *upload_data,
                              size_t *upload_data_size, void **con_cls) {

    /* OPTIONS preflight */
    if (strcmp(method, "OPTIONS") == 0) {
        return handle_options(connection);
    }

    /* Accumulate POST/PUT body */
    if (strcmp(method, "POST") == 0 || strcmp(method, "PUT") == 0) {
        if (*con_cls == NULL) {
            struct connection_info *ci = calloc(1, sizeof(struct connection_info));
            ci->data = NULL;
            ci->data_size = 0;
            *con_cls = ci;
            return MHD_YES;
        }
        struct connection_info *ci = *con_cls;
        if (*upload_data_size > 0) {
            size_t new_size = ci->data_size + *upload_data_size;
            if (new_size > MAX_BODY_SIZE) {
                *upload_data_size = 0;
                return send_json(connection, "{\"error\":\"body too large\"}", MHD_HTTP_PAYLOAD_TOO_LARGE);
            }
            ci->data = realloc(ci->data, new_size + 1);
            memcpy(ci->data + ci->data_size, upload_data, *upload_data_size);
            ci->data_size = new_size;
            ci->data[new_size] = '\0';
            *upload_data_size = 0;
            return MHD_YES;
        }
        /* Body fully received, process below */
    } else if (strcmp(method, "DELETE") == 0) {
        if (*con_cls == NULL) {
            struct connection_info *ci = calloc(1, sizeof(struct connection_info));
            *con_cls = ci;
            return MHD_YES;
        }
        if (*upload_data_size > 0) {
            *upload_data_size = 0;
            return MHD_YES;
        }
    } else if (strcmp(method, "GET") == 0) {
        /* GET doesn't need body accumulation, but for consistency with MHD */
        if (*con_cls == NULL) {
            struct connection_info *ci = calloc(1, sizeof(struct connection_info));
            *con_cls = ci;
            return MHD_YES;
        }
    }

    /* Route: GET /api/notes */
    if (strcmp(url, "/api/notes") == 0 && strcmp(method, "GET") == 0) {
        const char *limit_str = MHD_lookup_connection_value(connection, MHD_GET_ARGUMENT_KIND, "limit");
        const char *offset_str = MHD_lookup_connection_value(connection, MHD_GET_ARGUMENT_KIND, "offset");
        int limit = 50;
        int offset = 0;
        if (limit_str) {
            limit = atoi(limit_str);
            if (limit <= 0) limit = 50;
            if (limit > 100) limit = 100;
        }
        if (offset_str) {
            offset = atoi(offset_str);
            if (offset < 0) offset = 0;
        }
        int total = get_total_notes_count();
        char *json = get_notes_paginated_json(limit, offset);
        char count_str[32];
        snprintf(count_str, sizeof(count_str), "%d", total);
        enum MHD_Result r = send_response(connection,
            json ? json : "[]", MHD_HTTP_OK, count_str);
        if (json) free(json);
        return r;
    }

    /* Route: POST /api/notes */
    if (strcmp(url, "/api/notes") == 0 && strcmp(method, "POST") == 0) {
        if (!api_key_valid(connection)) {
            return send_json(connection, "{\"error\":\"unauthorized\"}", MHD_HTTP_UNAUTHORIZED);
        }
        struct connection_info *ci = *con_cls;
        if (!ci || !ci->data || ci->data_size == 0) {
            return send_json(connection, "{\"error\":\"title is required\"}", MHD_HTTP_BAD_REQUEST);
        }
        char *title = json_get_string(ci->data, "title");
        char *content = json_get_string(ci->data, "content");
        if (!title_valid(title)) {
            if (title) free(title);
            if (content) free(content);
            return send_json(connection, "{\"error\":\"title is required\"}", MHD_HTTP_BAD_REQUEST);
        }
        int id = create_note(title, content ? content : "");
        if (id < 0) {
            free(title);
            if (content) free(content);
            return send_json(connection, "{\"error\":\"internal error\"}", MHD_HTTP_INTERNAL_SERVER_ERROR);
        }
        char *note_json = get_note_json(id);
        enum MHD_Result r;
        if (note_json) {
            r = send_json(connection, note_json, MHD_HTTP_CREATED);
            free(note_json);
        } else {
            /* fallback: build it manually */
            char buf[131072];
            snprintf(buf, sizeof(buf), "{\"id\":%d,\"title\":\"%s\",\"content\":\"%s\"}", id, title, content ? content : "");
            r = send_json(connection, buf, MHD_HTTP_CREATED);
        }
        free(title);
        if (content) free(content);
        return r;
    }

    /* Routes with ID: /api/notes/{id} */
    if (strncmp(url, "/api/notes/", 11) == 0 && strlen(url) > 11) {
        int id = parse_id_from_url(url);
        if (id < 0) {
            return send_json(connection, "{\"error\":\"not found\"}", MHD_HTTP_NOT_FOUND);
        }

        /* GET /api/notes/{id} */
        if (strcmp(method, "GET") == 0) {
            char *json = get_note_json(id);
            if (!json) {
                return send_json(connection, "{\"error\":\"not found\"}", MHD_HTTP_NOT_FOUND);
            }
            enum MHD_Result r = send_json(connection, json, MHD_HTTP_OK);
            free(json);
            return r;
        }

        /* PUT /api/notes/{id} */
        if (strcmp(method, "PUT") == 0) {
            if (!api_key_valid(connection)) {
                return send_json(connection, "{\"error\":\"unauthorized\"}", MHD_HTTP_UNAUTHORIZED);
            }
            struct connection_info *ci = *con_cls;
            if (!ci || !ci->data || ci->data_size == 0) {
                return send_json(connection, "{\"error\":\"title is required\"}", MHD_HTTP_BAD_REQUEST);
            }
            char *title = json_get_string(ci->data, "title");
            char *content = json_get_string(ci->data, "content");
            if (!title_valid(title)) {
                if (title) free(title);
                if (content) free(content);
                return send_json(connection, "{\"error\":\"title is required\"}", MHD_HTTP_BAD_REQUEST);
            }
            int result = update_note(id, title, content ? content : "");
            free(title);
            if (content) free(content);
            if (result == 1) {
                return send_json(connection, "{\"error\":\"not found\"}", MHD_HTTP_NOT_FOUND);
            }
            if (result < 0) {
                return send_json(connection, "{\"error\":\"internal error\"}", MHD_HTTP_INTERNAL_SERVER_ERROR);
            }
            char *note_json = get_note_json(id);
            if (!note_json) {
                return send_json(connection, "{\"error\":\"not found\"}", MHD_HTTP_NOT_FOUND);
            }
            enum MHD_Result r = send_json(connection, note_json, MHD_HTTP_OK);
            free(note_json);
            return r;
        }

        /* DELETE /api/notes/{id} */
        if (strcmp(method, "DELETE") == 0) {
            if (!api_key_valid(connection)) {
                return send_json(connection, "{\"error\":\"unauthorized\"}", MHD_HTTP_UNAUTHORIZED);
            }
            int result = delete_note(id);
            if (result == 1) {
                return send_json(connection, "{\"error\":\"not found\"}", MHD_HTTP_NOT_FOUND);
            }
            if (result < 0) {
                return send_json(connection, "{\"error\":\"internal error\"}", MHD_HTTP_INTERNAL_SERVER_ERROR);
            }
            return send_json(connection, "{\"status\":\"deleted\"}", MHD_HTTP_OK);
        }
    }

    return send_json(connection, "{\"error\":\"not found\"}", MHD_HTTP_NOT_FOUND);
}
